    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return {}; // Return empty vector on connection failure
    }
    auto conn = *conn_result;

    // Build the base query
    auto query = sqlgen::read<std::vector<Book>>;

    // Dynamically add WHERE clauses based on non-null filters
    if (filters.title_keyword || filters.min_year || filters.genre || filters.max_price) {
        auto condition = sqlgen::nothing;

        // Add title LIKE condition if title_keyword is provided
        if (filters.title_keyword) {
            condition = ("title"_c.like("%" + *filters.title_keyword + "%"));
        }

        // Add year >= condition if min_year is provided
        if (filters.min_year) {
            condition = condition && ("year"_c >= *filters.min_year);
        }

        // Add genre = condition if genre is provided  
        if (filters.genre) {
            condition = condition && ("genre"_c == *filters.genre);
        }

        // Add price <= condition if max_price is provided
        if (filters.max_price) {
            condition = condition && ("price"_c <= *filters.max_price);
