      using IteratorType = internal::iterator_t<
          transpilation::fields_to_named_tuple_t<TableTupleType, FieldsType>,
          decltype(_conn)>;

      using ContainerType = std::conditional_t<std::is_same_v<ToType, Nothing>,
                                               Range<IteratorType>, ToType>;
