  EXPECT_DOUBLE_EQ(laptop.ceil_price, 1000.0);
  EXPECT_DOUBLE_EQ(laptop.floor_price, 999.0);
  EXPECT_DOUBLE_EQ(laptop.rounded_price, 999.99);

