```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace concat_function {

struct Person {
  sqlgen::PrimaryKey<int> id;
  std::string first_name;
  std::string last_name;
};

struct FullName {
  std::string full_name;
};

/**
 * This function demonstrates CONCAT usage.
 * Returns: query value.
 */
inline auto concat_function() {
    using namespace sqlgen::literals;

    // Create the query using sqlgen functions and operators
    auto query = sqlgen::select_from<Person>(
        sqlgen::concat("first_name"_c, " ", "last_name"_c) | sqlgen::as<"full_name">
    ) | sqlgen::to<FullName>;

    return query;
}

}  // namespace concat_function
```

## Explanation of Implementation:

1. **Namespace Usage**: `using namespace sqlgen::literals` enables the use of the `_c` literal suffix for column references.

2. **Query Construction**:
   - `sqlgen::select_from<Person>` starts the query on the Person table
   - `sqlgen::concat("first_name"_c, " ", "last_name"_c)` concatenates the first_name, a space, and last_name columns
   - `| sqlgen::as<"full_name">` applies the alias "full_name" to the concatenated result
   - `| sqlgen::to<FullName>` specifies the return type as the FullName struct

3. **Operator Chaining**: The `|` operator is used to chain the operations together in the correct sequence as specified in the requirements.

